#include <stdio.h>
#include <stdlib.h>

int main() {
    int n, m;
    scanf("%d %d", &n, &m);

    int *c = calloc(m, sizeof(int));
    int *d = calloc(m, sizeof(int));

    for (int i = 1; i <= m; i++) {
        c[(i * i) % m]++;
    }

    for (int i = 1; i <= n % m; i++) {
        d[(i * i) % m]++;
    }

    int *r = calloc(m, sizeof(int));
    for (int k = 0; k < m; k++) {
        r[k] = (n / m) * c[k] + d[k];
    }

    long long result = 0;
    for (int k = 0; k < m; k++) {
        result += r[k] * r[(m - k) % m];
    }

    printf("%lld\n", result);

    free(c);
    free(d);
    free(r);
    return 0;
}
